#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to perform preorder traversal iteratively
void preorderTraversal(Node* root) {
    if (root == NULL) return;

    // Create a stack and push the root node
    Node** stack = (Node**) malloc(sizeof(Node*) * 1000);
    int top = -1;
    stack[++top] = root;

    while (top != -1) {
        Node* temp = stack[top--];
        printf("%d ", temp->val);

        // Push right and left children into the stack
        if (temp->right) stack[++top] = temp->right;
        if (temp->left) stack[++top] = temp->left;
    }
    free(stack);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Node* root = NULL;
        Node** nodes = (Node**) malloc(sizeof(Node*) * N);
        for (int i = 0; i < N; i++) {
            int val;
            scanf("%d", &val);
            if (val == -1) {
                nodes[i] = NULL;
            } else {
                nodes[i] = createNode(val);
            }
        }
        // Create the binary tree from the level-order traversal
        if (N > 0 && nodes[0] != NULL) {
            root = nodes[0];
            int index = 0;
            for (int i = 0; i < N; i++) {
                if (nodes[i] == NULL) continue;
                index++;
                if (index < N) nodes[i]->left = nodes[index];
                index++;
                if (index < N) nodes[i]->right = nodes[index];
            }
        }
        preorderTraversal(root);
        printf("\n");
        free(nodes);
    }
    return 0;
}

