import java.util.Stack;
import java.util.Scanner;

public class Main {
    // Define the structure for a tree node
    static class Node {
        int val;
        Node left;
        Node right;

        public Node(int val) {
            this.val = val;
            this.left = null;
            this.right = null;
        }
    }

    // Function to perform preorder traversal iteratively
    public static void preorderTraversal(Node root) {
        if (root == null) return;

        // Create a stack and push the root node
        Stack<Node> stack = new Stack<>();
        stack.push(root);

        while (!stack.isEmpty()) {
            Node temp = stack.pop();
            System.out.print(temp.val + " ");

            // Push right and left children into the stack
            if (temp.right != null) stack.push(temp.right);
            if (temp.left != null) stack.push(temp.left);
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            Node[] nodes = new Node[N];
            for (int i = 0; i < N; i++) {
                int val = scanner.nextInt();
                if (val == -1) {
                    nodes[i] = null;
                } else {
                    nodes[i] = new Node(val);
                }
            }
            // Create the binary tree from the level-order traversal
            Node root = null;
            if (N > 0 && nodes[0] != null) {
                root = nodes[0];
                int index = 0;
                for (int i = 0; i < N; i++) {
                    if (nodes[i] == null) continue;
                    index++;
                    if (index < N) nodes[i].left = nodes[index];
                    index++;
                    if (index < N) nodes[i].right = nodes[index];
                }
            }
            preorderTraversal(root);
            System.out.println();
        }
    }
}

